import java.lang.Math;

public class MathUtils{

   public static final double EPSILON = 0.00001f;

   /** 
    * Determines whether two doubles are equal within tolerance limits.
    * Tests for equality of two Doubles including checking against the NaN case.
    * @param x The first Double.
    * @param y The second Double.
    * @return a boolean value indicating whether they are equal or not.
    */    
   public static boolean equals(double x, double y){
       //Checking if both are NaN
       if(Double.isNaN(x)&&Double.isNaN(y)){
           return true;
       }
       else if((Double.isNaN(x)&&!Double.isNaN(y))||(!Double.isNaN(x)&&Double.isNaN(y))) {
       		return false;
       }else {
            return Math.abs(x - y) < EPSILON;
        }
   }

}

